import React from 'react';

const Cultura = ({ sitios, tipo }) => {
    // Esta lógica permite que si entras a "Museos", filtre por Museos.
    // Si entras a "Teatros", filtre por Teatros.
    // Y si por alguna razón no hay tipo, muestre todo (sin quitar nada).
    const sitiosFiltrados = sitios.filter(sitio => {
        if (!tipo) return true; // Si no hay tipo, muestra todo lo que hay en la BD
        
        const nombreBuscado = sitio.nombre.toLowerCase();
        const tipoBuscado = tipo.toLowerCase();
        
        // Filtra si el nombre contiene la palabra (ej: "Teatro Municipal") 
        // o si tienes una columna id_categoria (por ahora usamos el nombre)
        return nombreBuscado.includes(tipoBuscado);
    });

    return (
        <div className="layout">
            {/* --- HERO / BANNER DINÁMICO --- */}
            <section className="hero-banner">
                <div className="hero-content">
                    {/* El título cambia según la pestaña, pero la base es la misma */}
                    <h1>{tipo ? `${tipo}s de La Paz` : 'Patrimonio Cultural'}</h1>
                    <p>Gestión centralizada de espacios culturales para la ciudad</p>
                </div>
            </section>

            {/* --- BODY / GRILLA DE TARJETAS --- */}
            <main className="container">
                <div className="grid-container">
                    {sitiosFiltrados && sitiosFiltrados.length > 0 ? (
                        sitiosFiltrados.map((sitio) => (
                            <div key={sitio.id_sitio} className="card">
                                <div className="card-content">
                                    {/* Mantenemos todos los datos que ya tenías */}
                                    <h2>{sitio.nombre}</h2>
                                    <p>{sitio.descripcion}</p>
                                    <hr style={{ margin: '15px 0', border: '0', borderTop: '1px solid #eee' }} />
                                    <div className="card-footer">
                                        <small>📍 {sitio.direccion}</small>
                                    </div>
                                </div>
                            </div>
                        ))
                    ) : (
                        <div className="no-data" style={{ textAlign: 'center', gridColumn: '1 / -1', padding: '50px' }}>
                            <h3>No hay {tipo ? tipo.toLowerCase() : 'registros'} disponibles</h3>
                            <p>Verifica los datos en tu tabla de PostgreSQL.</p>
                        </div>
                    )}
                </div>
            </main>
        </div>
    );
};

export default Cultura;
